    // Get output format from event metadata
    const outputFormat = record.s3.object.metadata?.outputformat?.toLowerCase();
    if (!outputFormat || !ALLOWED_FORMATS.has(outputFormat)) {
      throw new Error('Invalid output format');
    }
    
    // Validate file size
    const headResult = await s3.headObject({ Bucket: bucket, Key: key }).promise();
    if (headResult.ContentLength > MAX_FILE_SIZE) {
      throw new Error('File too large');
    }
    
    // Generate output key
    const outputKey = key.replace(new RegExp(`\\.${fileExtension}$`), `.${outputFormat}`);
    
    // Download image from S3
    const s3Object = await s3.getObject({ Bucket: bucket, Key: key }).promise();
    
    // Convert image using ImageMagick
    const tempInputPath = `/tmp/${Date.now()}-${key.split('/').pop()}`;
    const tempOutputPath = `/tmp/${Date.now()}-${outputKey.split('/').pop()}`;
    
    // Write input to temp file
    require('fs').writeFileSync(tempInputPath, s3Object.Body);
    
    // Execute convert command
    const command = `convert "${tempInputPath}" -quality 90 "${tempOutputPath}"`;
    await execPromise(command);
    
    // Upload converted image to S3
    const outputBuffer = require('fs').readFileSync(tempOutputPath);
    await s3.putObject({
      Bucket: bucket,
      Key: outputKey,
      Body: outputBuffer,
      ContentType: `image/${outputFormat}`
    }).promise();
    
    // Clean up temp files
    require('fs').unlinkSync(tempInputPath);
    require('fs').unlinkSync(tempOutputOutputPath);
    
    return {
      statusCode: 200,
      body: JSON.stringify({
        message: 'Image converted successfully',
        inputKey: key,
        outputKey: outputKey
      })
    };
